create table if not exists settings (id bigint generated by default as identity primary key, key text unique not null, value jsonb not null, updated_at timestamp with time zone default now());
create table if not exists news (id bigint generated by default as identity primary key, title text not null, text text not null, date text, created_at timestamp with time zone default now());
create table if not exists media (id bigint generated by default as identity primary key, title text not null, type text not null, url text not null, created_at timestamp with time zone default now());
create table if not exists fixture (id bigint generated by default as identity primary key, date text, serie text, game text, place text, hour text, created_at timestamp with time zone default now());
create table if not exists standings (id bigint generated by default as identity primary key, serie text, team text, pj int default 0, pg int default 0, pe int default 0, pp int default 0, dg text default '0', pts int default 0, created_at timestamp with time zone default now());
create table if not exists sponsors (id bigint generated by default as identity primary key, name text not null, url text not null, created_at timestamp with time zone default now());
create table if not exists member_requests (id bigint generated by default as identity primary key, name text, rut text, phone text, type text, status text default 'pendiente', created_at timestamp with time zone default now());
